mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT MEMBERID AS memberId, NAME AS name, EMAIL AS email, STATUS AS status, CREATED_AT AS createdAt, LAST_LOGIN_AT AS lastLoginAt FROM TBL_MEMBER
TYPE = 0
AND ( NAME LIKE '%' || #{search} || '%' OR EMAIL LIKE '%' || #{search} || '%' )
AND STATUS = #{status}
ORDER BY CREATED_AT DESC ) a WHERE ROWNUM <= #{endRow} ) WHERE rn > #{offset}
